const body = $input.first().json.body || $input.first().json;
const recordId = body.record_id || body.recordId || body.id;

if (!recordId) {
  throw new Error('Missing record_id in webhook payload from Airtable automation');
}

return [{ json: {
  record_id: recordId,
  triggered_at: new Date().toISOString()
}}];

const row = $input.first().json;
const f = row.fields || {};
const title = f.Title || f.title || '';
const url = f['URL'] || f.url || '';
const keyword = f['Target keyword'] || f.target_keyword || '';
const summary = f['Summary'] || f.summary || f.Body?.slice(0, 500) || '';

if (!title || !url) {
  throw new Error('Blog row missing Title or URL');
}

const prompt = `You are a Pinterest content strategist for The STR Ledger, an editorial-finance brand selling Excel workbooks for Airbnb/VRBO hosts. Generate exactly 5 Pinterest pin variants for this blog post.\n\nBlog title: ${title}\nBlog URL: ${url}\nTarget keyword: ${keyword}\nSummary: ${summary}\n\nReturn a JSON array of exactly 5 objects, one for each variant_type in this order: tip-list, quote-card, infographic, question, before-after.\n\nEach object must have:\n  - variant_type (string, one of the 5 above)\n  - pin_title (string, max 100 chars, hook-driven)\n  - pin_description (string, 200-500 chars, includes target keyword and CTA to read the post)\n  - hashtags (array of 5-8 strings, no '#' prefix, lowercase, relevant to short-term-rental hosts)\n\nReturn ONLY the JSON array, no markdown, no commentary.`;

return [{ json: {
  blog_record_id: row.id,
  blog_title: title,
  blog_url: url,
  blog_keyword: keyword,
  prompt: prompt,
  triggered_at: $node['Extract Blog Record ID'].json.triggered_at
}}];

const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';

if (!text) throw new Error('Claude returned empty content');

// Strip markdown code fences if present
let cleaned = text.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '').trim();

let variants;
try {
  variants = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + ' | raw: ' + cleaned.slice(0, 300));
}

if (!Array.isArray(variants) || variants.length === 0) {
  throw new Error('Claude did not return a non-empty array');
}

const ctx = $node['Build Claude Pin Prompt'].json;

// Map variant_type to Vista Create template id (placeholders — replace with real ids)
const templateMap = {
  'tip-list': $env.VISTA_TEMPLATE_TIP_LIST || 'tmpl-tip-list-001',
  'quote-card': $env.VISTA_TEMPLATE_QUOTE || 'tmpl-quote-card-001',
  'infographic': $env.VISTA_TEMPLATE_INFOGRAPHIC || 'tmpl-infographic-001',
  'question': $env.VISTA_TEMPLATE_QUESTION || 'tmpl-question-001',
  'before-after': $env.VISTA_TEMPLATE_BEFORE_AFTER || 'tmpl-before-after-001'
};

return variants.map((v, idx) => ({ json: {
  index: idx,
  variant_type: v.variant_type,
  pin_title: v.pin_title,
  pin_description: v.pin_description,
  hashtags: Array.isArray(v.hashtags) ? v.hashtags : [],
  vista_template_id: templateMap[v.variant_type] || templateMap['tip-list'],
  blog_record_id: ctx.blog_record_id,
  blog_title: ctx.blog_title,
  blog_url: ctx.blog_url,
  blog_keyword: ctx.blog_keyword
}}));

// Runs once after the variant loop finishes (SplitInBatches 'done' branch)
const ctx = $node['Build Claude Pin Prompt'].json;
const variantCount = $items('Parse Pin Variants', 0, 0).length;

const prompt = `You are an email copywriter for The STR Ledger newsletter (audience: Airbnb/VRBO hosts who run their business with spreadsheets). Write a short broadcast email announcing this new blog post.\n\nBlog title: ${ctx.blog_title}\nBlog URL: ${ctx.blog_url}\nTarget keyword: ${ctx.blog_keyword}\n\nReturn a JSON object with exactly two keys:\n  - subject (string, max 60 chars, plain text, no emoji unless the brand voice clearly calls for one)\n  - body_markdown (string, 150-300 words, markdown-formatted, ends with a clear CTA link to the blog URL)\n\nVoice: editorial, dry-confident, host-to-host. No hype, no exclamation marks. Lead with the problem the post solves.\n\nReturn ONLY the JSON object, no markdown fence, no commentary.`;

return [{ json: {
  blog_record_id: ctx.blog_record_id,
  blog_title: ctx.blog_title,
  blog_url: ctx.blog_url,
  variant_count: variantCount,
  prompt: prompt
}}];

const resp = $input.first().json;
const text = resp.content?.[0]?.text || '';
if (!text) throw new Error('Claude returned empty email content');

let cleaned = text.trim();
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/^```\s*/, '').replace(/```\s*$/, '').trim();

let email;
try {
  email = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Claude email JSON: ' + e.message + ' | raw: ' + cleaned.slice(0, 300));
}

if (!email.subject || !email.body_markdown) {
  throw new Error('Email JSON missing subject or body_markdown');
}

const ctx = $node['Build Email Prompt'].json;

return [{ json: {
  subject: email.subject,
  body_markdown: email.body_markdown,
  blog_record_id: ctx.blog_record_id,
  blog_title: ctx.blog_title,
  blog_url: ctx.blog_url,
  variant_count: ctx.variant_count
}}];

const input = $input.first().json;
return [{ json: {
  timestamp: new Date().toISOString(),
  workflow: 'W16-blog-post-promotion-cascade',
  node: $node.name || 'unknown',
  error_message: input.error?.message || JSON.stringify(input).slice(0, 500),
  payload: JSON.stringify(input).slice(0, 500),
  status: 'Open'
}}];
